const gallery = document.querySelector('.galleryList');

const imgItem = images.map(item => {
  const img = document.createElement('img');
  const link = document.createElement('a');
  const listItem = document.createElement('li');
  img.setAttribute('src', item.preview);
  img.setAttribute('alt', item.description);
  link.setAttribute('href', item.original);
  listItem.setAttribute('class', 'galleryItem');
  link.append(img);
  listItem.append(link);
  return listItem;
});
gallery.append(...imgItem);

const galleryLightBox = new SimpleLightbox('.galleryList a', {
  captions: true,
  captionSelector: 'img',
  captionsData: 'alt',
  captionPosition: 'bottom',
  captionDelay: '250ms',
});

galleryLightBox.on('show.simplelightbox', function (e) {});
galleryLightBox.on('error.simplelightbox', function (e) {
  console.log(e);
});
